const input = $input.first().json;
const businessId = input.body.businessId;
const businessName = input.body.businessName;
const businessDescription = input.body.businessDescription || '';
const category = input.body.category || 'unknown';
const opportunityData = input.body.opportunityData || {};

if (!businessId || !businessName) {
  throw new Error('Missing required fields: businessId and businessName');
}

return [{
  json: {
    businessId,
    businessName,
    businessDescription,
    category,
    opportunityData,
    startedAt: new Date().toISOString()
  }
}];

const bootstrapResult = $input.first().json;
const payload = $('Extract Payload').first().json;

const success = bootstrapResult.status === 'success' || bootstrapResult.status === 'skipped';
const message = bootstrapResult.message || 'No message';

return [{
  json: {
    ...payload,
    bootstrapStatus: bootstrapResult.status || 'unknown',
    bootstrapSuccess: success,
    bootstrapMessage: message
  }
}];

