// Initialize iteration counter
const payload = $('Extract Payload').first().json;
return [{
  json: {
    ...payload,
    iterationCount: 0,
    lastScore: 0,
    iterationHistory: [],
    siteUrl: 'https://' + payload.businessId + '.vercel.app'
  }
}];

const testResult = $input.first().json;
const prevData = $('Init Iteration Counter').isPresent
  ? $('Init Iteration Counter').first().json
  : $('Increment Iteration').first().json;

// Extract score from test result
const score = testResult.score || testResult.health_score || testResult.overall_score || 0;
const issuesCreated = testResult.issues_created || testResult.issuesCreated || 0;
const details = testResult.details || testResult.summary || testResult.message || 'No details';

const iterationCount = (prevData.iterationCount || 0) + 1;
const iterationHistory = [...(prevData.iterationHistory || []), {
  iteration: iterationCount,
  score,
  issuesCreated,
  timestamp: $now.toFormat('yyyy-MM-dd HH:mm')
}];

return [{
  json: {
    businessId: prevData.businessId,
    businessName: prevData.businessName,
    businessDescription: prevData.businessDescription || '',
    category: prevData.category || '',
    siteUrl: prevData.siteUrl,
    iterationCount,
    lastScore: score,
    issuesCreated,
    testDetails: typeof details === 'string' ? details : JSON.stringify(details, null, 2),
    iterationHistory,
    scorePassThreshold: score >= 80,
    maxIterationsReached: iterationCount >= 3
  }
}];

