const testResult = $input.first().json;
const prevData = $('Increment Iteration 2').first().json;

const score = testResult.score || testResult.health_score || testResult.overall_score || 0;
const issuesCreated = testResult.issues_created || testResult.issuesCreated || 0;

const iterationCount = (prevData.iterationCount || 0) + 1;
const iterationHistory = [...(prevData.iterationHistory || []), {
  iteration: iterationCount,
  score,
  issuesCreated,
  timestamp: $now.toFormat('yyyy-MM-dd HH:mm')
}];

return [{
  json: {
    businessId: prevData.businessId,
    businessName: prevData.businessName,
    businessDescription: prevData.businessDescription || '',
    category: prevData.category || '',
    siteUrl: prevData.siteUrl,
    iterationCount,
    lastScore: score,
    iterationHistory
  }
}];

// Merge iteration data and prepare for quality gate
// This node collects from whichever path we arrived from
let data;

// Try to get data from the various possible paths
try { data = $('Parse Test Result').first().json; } catch(e) {}
if (!data) try { data = $('Parse Test Result (Retry)').first().json; } catch(e) {}
if (!data) try { data = $('Parse Test Result (Final)').first().json; } catch(e) {}
if (!data) try { data = $('Notify: Final Iteration').first().json; } catch(e) {}
if (!data) {
  // Fallback
  data = $input.first().json;
}

const iterationSummary = (data.iterationHistory || []).map(h =>
  `Iteration ${h.iteration}: score ${h.score}/100 (${h.timestamp})`
).join('\n');

return [{
  json: {
    businessId: data.businessId,
    businessName: data.businessName,
    businessDescription: data.businessDescription || '',
    category: data.category || '',
    siteUrl: data.siteUrl || 'https://' + data.businessId + '.vercel.app',
    finalScore: data.lastScore || 0,
    totalIterations: data.iterationCount || 0,
    iterationSummary,
    iterationHistory: data.iterationHistory || []
  }
}];

const qgResult = $input.first().json;
const payload = $('Prepare Quality Gate').first().json;

const passed = qgResult.passed === true || qgResult.status === 'passed' || qgResult.result === 'pass';
const score = qgResult.score || qgResult.overall_score || 'N/A';
const details = qgResult.details || qgResult.checks || qgResult.message || 'No details';
const failures = qgResult.failures || qgResult.failed_checks || [];

return [{
  json: {
    ...payload,
    qgPassed: passed,
    qgScore: score,
    qgDetails: typeof details === 'string' ? details : JSON.stringify(details, null, 2),
    qgFailures: Array.isArray(failures) ? failures : []
  }
}];

