const data = $('Parse Quality Gate Result').first().json;
const failures = data.qgFailures;
const businessId = data.businessId;
const businessName = data.businessName;

if (failures.length === 0) {
  return [{
    json: {
      owner: 'Sluice-Organization',
      repo: businessId,
      title: '@claude [Remediation] Quality gate failed for ' + businessName,
      body: '@claude The quality gate check failed for ' + businessName + '.\n\nDetails:\n' + data.qgDetails + '\n\nPlease investigate and fix all failing checks. Then create a PR with the fixes.'
    }
  }];
}

return failures.map((failure, i) => ({
  json: {
    owner: 'Sluice-Organization',
    repo: businessId,
    title: '@claude [Remediation ' + (i + 1) + '] ' + (typeof failure === 'string' ? failure : (failure.check || failure.name || 'Fix quality issue')),
    body: '@claude Quality gate check failed:\n\n' + (typeof failure === 'string' ? failure : JSON.stringify(failure, null, 2)) + '\n\nPlease fix this issue and create a PR with the changes.'
  }
}));
